void listenToDeepLinks() async {
  if (await UniLinks.hasPendingLink()) {
    final initialLink = await getInitialLink();
    _handleDeepLink(initialLink);
  }

  unlinked.stream.listen((String? link) {
    if (link != null) {
      _handleDeepLink(Uri.parse(link));
    }
  });
}

void _handleDeepLink(Uri? deepLink) {
  if (deepLink != null) {
    switch (deepLink.path) {
      case '/profile':
        Navigator.pushNamed(
          navigatorKey.currentContext!,
          ProfileScreen.routeName,
          arguments: ProfileScreen.fromDeepLink(deepLink),
        );
        break;
      case '/payment/confirm':
        Navigator.pushNamed(navigatorKey.currentContext!, '/payment/confirm');
        break;
    }
  }
}